const now = new Date();
now.setHours(now.getHours() + 2);
const start = now.toISOString();
const end_date = new Date(now.getTime() + 5 * 24 * 60 * 60 * 1000);
const end = end_date.toISOString();

const url = 'https://api.calendly.com/event_type_available_times?event_type=https://api.calendly.com/event_types/5277bfb6-29bf-48e0-81c0-24e8aeab6bab&start_time=' + encodeURIComponent(start) + '&end_time=' + encodeURIComponent(end);

const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: url,
  headers: {
    'Authorization': 'Bearer eyJraWQiOiIxY2UxZTEzNjE3ZGNmNzY2YjNjZWJjY2Y4ZGM1YmFmYThhNjVlNjg0MDIzZjdjMzJiZTgzNDliMjM4MDEzNWI0IiwidHlwIjoiUEFUIiwiYWxnIjoiRVMyNTYifQ..zFXmn1Tw-PE3s9rRDny9Gczqk8CpRhv2SqO6rWeX5LSgGUrnpRjlxSVRXsq6qTyFPnaw-jIzEuu239cgQEZYIg'
  }
});

const slots = resp.collection || [];
const available = slots.slice(0, 6).map(s => {
  const d = new Date(s.start_time);
  const day = d.toLocaleDateString('en-AU', { weekday: 'long', month: 'short', day: 'numeric', timeZone: 'Australia/Brisbane' });
  const time = d.toLocaleTimeString('en-AU', { hour: 'numeric', minute: '2-digit', hour12: true, timeZone: 'Australia/Brisbane' });
  return day + ' at ' + time;
});

const toolCallId = $('Webhook').first().json?.body?.message?.toolCallList?.[0]?.id || 'unknown';

const result = available.length > 0
  ? 'Available times in the next few days: ' + available.join(', ') + '. Ask which one works best for them.'
  : 'No available times right now. Ask the caller to visit calendly.com/aestheticcal22/30min to check other dates.';

return [{ json: { results: [{ toolCallId: toolCallId, result: result }] } }];
